    // Async command methods

    /// <summary>Send SetpointRaiseLower command (0x0000).</summary>
    public Task<InvokeResponse> SetpointRaiseLowerAsync(
        SetpointRaiseLowerModeEnum mode,
        sbyte amount,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0000, tlv =>
        {
            tlv.AddUInt8(0, (byte)mode);
            tlv.AddInt8(1, amount);
        }, ct);

    /// <summary>Send SetWeeklySchedule command (0x0001).</summary>
    public Task<InvokeResponse> SetWeeklyScheduleAsync(
        byte numberOfTransitionsForSequence,
        ScheduleDayOfWeekBitmap dayOfWeekForSequence,
        ScheduleModeBitmap modeForSequence,
        WeeklyScheduleTransitionStruct[] transitions,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0001, tlv =>
        {
            tlv.AddUInt8(0, numberOfTransitionsForSequence);
            tlv.AddUInt8(1, (byte)dayOfWeekForSequence);
            tlv.AddUInt8(2, (byte)modeForSequence);
            if (transitions != null) { tlv.AddArray(3); foreach (var item in transitions) { WriteWeeklyScheduleTransitionStruct(tlv, item); } tlv.EndContainer(); }
        }, ct);

