    /// <summary>Send AtomicRequest command (0x00FE).</summary>
    public Task<InvokeResponse> AtomicRequestAsync(
        AtomicRequestTypeEnum requestType,
        uint[] attributeRequests,
        ushort? timeout = default,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x00FE, tlv =>
        {
            tlv.AddUInt8(0, (byte)requestType);
            if (attributeRequests != null) { tlv.AddArray(0); foreach (var item in attributeRequests) { tlv.AddUInt32(item); } tlv.EndContainer(); }
            if (timeout != null) tlv.AddUInt16(0, timeout.Value);
        }, ct);

